import { useState, useCallback } from 'react';
import {
  Card,
  CardBody,
  CardTitle,
  CardExpandableContent,
  CardHeader,
  Label,
  Flex,
  FlexItem,
  List,
  ListItem,
  Icon,
} from '@patternfly/react-core';
import {
  CheckCircleIcon,
  ExclamationCircleIcon,
  OutlinedCircleIcon,
} from '@patternfly/react-icons';
import type { Feature } from '../state/store';

export interface KanbanCardProps {
  feature: Feature;
}

const priorityColors: Record<string, 'red' | 'orange' | 'blue' | 'grey'> = {
  critical: 'red',
  high: 'orange',
  medium: 'blue',
  low: 'grey',
};

const categoryColors: Record<string, 'purple' | 'teal' | 'green' | 'grey'> = {
  core: 'purple',
  ui: 'teal',
  setup: 'green',
};

export function KanbanCard({ feature }: KanbanCardProps) {
  const [isExpanded, setIsExpanded] = useState(false);

  const handleExpand = useCallback(() => {
    setIsExpanded((prev) => !prev);
  }, []);

  const priorityColor = priorityColors[feature.priority] || 'grey';
  const categoryColor = categoryColors[feature.category] || 'grey';

  return (
    <Card
      id={`kanban-card-${feature.id}`}
      isExpanded={isExpanded}
      isCompact
      style={{ marginBottom: '8px' }}
    >
      <CardHeader
        onExpand={handleExpand}
        isToggleRightAligned
        toggleButtonProps={{
          id: `toggle-${feature.id}`,
          'aria-label': isExpanded ? 'Collapse' : 'Expand',
        }}
      >
        <CardTitle>
          <Flex
            direction={{ default: 'column' }}
            spaceItems={{ default: 'spaceItemsSm' }}
          >
            <FlexItem>
              <Flex spaceItems={{ default: 'spaceItemsSm' }}>
                <FlexItem>
                  <Label color={feature.passes ? 'green' : 'yellow'} isCompact>
                    {feature.id}
                  </Label>
                </FlexItem>
                <FlexItem>
                  <Label color={priorityColor} isCompact>
                    {feature.priority}
                  </Label>
                </FlexItem>
                <FlexItem>
                  <Label color={categoryColor} isCompact>
                    {feature.category}
                  </Label>
                </FlexItem>
              </Flex>
            </FlexItem>
            <FlexItem>
              <span style={{ fontSize: '0.9rem', fontWeight: 500 }}>
                {feature.description.split(' - ')[0]}
              </span>
            </FlexItem>
          </Flex>
        </CardTitle>
      </CardHeader>
      <CardExpandableContent>
        <CardBody>
          <p style={{ marginBottom: '12px', color: '#6a6e73' }}>
            {feature.description}
          </p>
          <strong>Steps:</strong>
          <List isPlain style={{ marginTop: '8px' }}>
            {feature.steps.map((step, idx) => (
              <ListItem key={idx} icon={<StepIcon passes={feature.passes} />}>
                {step}
              </ListItem>
            ))}
          </List>
        </CardBody>
      </CardExpandableContent>
    </Card>
  );
}

function StepIcon({ passes }: { passes: boolean }) {
  if (passes) {
    return (
      <Icon status="success">
        <CheckCircleIcon />
      </Icon>
    );
  }
  return (
    <Icon status="warning">
      <OutlinedCircleIcon />
    </Icon>
  );
}

export default KanbanCard;

import {
  Flex,
  FlexItem,
  Card,
  CardHeader,
  CardTitle,
  CardBody,
  Badge,
  Content,
} from '@patternfly/react-core';
import { KanbanCard } from './KanbanCard';
import type { Feature } from '../state/store';

export interface KanbanBoardProps {
  features: Feature[];
}

// Column definitions with status mapping
const COLUMNS = [
  { id: 'backlog', title: 'BACKLOG', statuses: ['backlog'] },
  { id: 'todo', title: 'TODO', statuses: ['todo', 'pending'] },
  { id: 'doing', title: 'DOING', statuses: ['doing', 'in_progress', 'wip'] },
  { id: 'review', title: 'REVIEW', statuses: ['review', 'pr'] },
  { id: 'qa', title: 'QA', statuses: ['qa', 'testing'] },
  { id: 'done', title: 'DONE', statuses: ['done', 'completed', 'passed'] },
] as const;

// Map feature to column based on status and passes flag
function getColumnForFeature(feature: Feature): string {
  // If feature passes, it's DONE regardless of status
  if (feature.passes) {
    return 'done';
  }

  const status = feature.status.toLowerCase();

  for (const column of COLUMNS) {
    if (column.statuses.some((s) => status.includes(s))) {
      return column.id;
    }
  }

  // Default to backlog if status not recognized
  return 'backlog';
}

// Group features by column
function groupByColumn(features: Feature[]): Record<string, Feature[]> {
  const grouped: Record<string, Feature[]> = {};

  // Initialize all columns
  for (const column of COLUMNS) {
    grouped[column.id] = [];
  }

  // Sort features into columns
  for (const feature of features) {
    const columnId = getColumnForFeature(feature);
    grouped[columnId].push(feature);
  }

  // Sort features within each column by priority
  const priorityOrder: Record<string, number> = {
    critical: 0,
    high: 1,
    medium: 2,
    low: 3,
  };

  for (const columnId of Object.keys(grouped)) {
    grouped[columnId].sort((a, b) => {
      const aPriority = priorityOrder[a.priority] ?? 4;
      const bPriority = priorityOrder[b.priority] ?? 4;
      return aPriority - bPriority;
    });
  }

  return grouped;
}

const columnStyles: React.CSSProperties = {
  minWidth: '220px',
  maxWidth: '280px',
  flex: '1 1 220px',
  height: '100%',
  display: 'flex',
  flexDirection: 'column',
};

const columnHeaderStyles: React.CSSProperties = {
  backgroundColor: '#f0f0f0',
  borderBottom: '2px solid #06c',
};

const columnBodyStyles: React.CSSProperties = {
  backgroundColor: '#fafafa',
  flex: 1,
  overflowY: 'auto',
  padding: '8px',
  minHeight: '200px',
};

export function KanbanBoard({ features }: KanbanBoardProps) {
  const grouped = groupByColumn(features);

  return (
    <div
      style={{
        width: '100%',
        overflowX: 'auto',
        padding: '8px 0',
      }}
    >
      <Flex
        spaceItems={{ default: 'spaceItemsMd' }}
        alignItems={{ default: 'alignItemsStretch' }}
        style={{ minWidth: 'max-content' }}
      >
        {COLUMNS.map((column) => {
          const columnFeatures = grouped[column.id];
          const count = columnFeatures.length;

          return (
            <FlexItem key={column.id} style={columnStyles}>
              <Card isFlat isFullHeight>
                <CardHeader style={columnHeaderStyles}>
                  <CardTitle>
                    <Flex
                      justifyContent={{ default: 'justifyContentSpaceBetween' }}
                      alignItems={{ default: 'alignItemsCenter' }}
                    >
                      <FlexItem>
                        <strong>{column.title}</strong>
                      </FlexItem>
                      <FlexItem>
                        <Badge isRead={count === 0}>{count}</Badge>
                      </FlexItem>
                    </Flex>
                  </CardTitle>
                </CardHeader>
                <CardBody style={columnBodyStyles}>
                  {columnFeatures.length > 0 ? (
                    columnFeatures.map((feature) => (
                      <KanbanCard key={feature.id} feature={feature} />
                    ))
                  ) : (
                    <Content
                      component="p"
                      style={{
                        textAlign: 'center',
                        color: '#6a6e73',
                        fontStyle: 'italic',
                        padding: '16px',
                      }}
                    >
                      No features
                    </Content>
                  )}
                </CardBody>
              </Card>
            </FlexItem>
          );
        })}
      </Flex>
    </div>
  );
}

export default KanbanBoard;

